    32	        for (int s=0;s<(14-(frame_parms->Ncp<<1));s++) {
    33	          offset = offset0 + (s*frame_parms->ofdm_symbol_size);
    34	          ul_ch = (c16_t *)&common_vars->rxdataF[aarx][offset];
    35	          len = 12;
    36		// just do first half of middle PRB for odd number of PRBs
    37		        if (((frame_parms->N_RB_UL&1) == 1) && 
    38		            (rb==(frame_parms->N_RB_UL>>1))) {
    39		           len=6;
    40		        }
    41	
    42		        AssertFatal(ul_ch, "RX signal buffer (freq) problem");
    43	
    44	
    45		        measurements->n0_subband_power[aarx][rb] += signal_energy_nodc(ul_ch,len);
    46		  
    47	        } // symbol
    48	        measurements->n0_subband_power[aarx][rb]/=(14-(frame_parms->Ncp<<1));
    49	        measurements->n0_subband_power_dB[aarx][rb] = dB_fixed(measurements->n0_subband_power[aarx][rb]);
    50	        n0_power_tot += measurements->n0_subband_power[aarx][rb];
    51	
    52	      } //antenna
    53	      n0_power_tot/=frame_parms->nb_antennas_rx;
    54	      n0_power_tot2 += n0_power_tot;
    55	      measurements->n0_subband_power_tot_dB[rb] = dB_fixed(n0_power_tot);
    56	      measurements->n0_subband_power_tot_dBm[rb] = measurements->n0_subband_power_tot_dB[rb] - eNB->rx_total_gain_dB - dB_fixed(frame_parms->N_RB_UL);
    57	      
    58	    } //rb not used in subframe
    59	  } //rb
    60	  if (nb_rb>0) measurements->n0_subband_power_avg_dB = dB_fixed(n0_power_tot2/nb_rb);
    61	}

      measurements->n0_subband_power_tot_dB[rb] = dB_fixed(n0_power_tot);
      measurements->n0_subband_power_tot_dBm[rb] = measurements->n0_subband_power_tot_dB[rb] - eNB->rx_total_gain_dB - dB_fixed(frame_parms->N_RB_UL);

    } //rb not used in subframe
  } //rb
  if (nb_rb>0) measurements->n0_subband_power_avg_dB = dB_fixed(n0_power_tot2/nb_rb);
}

